import { pick } from '../../../utils/zcutils';
import { svgBoxShadow } from '../../../utils/zcsvgutils';

export function handleShadow(filterConfig, handles, ele, chart) {
    let handleType = filterConfig.type;

    if (handleType) {
        let shadow = pick(filterConfig[handleType].shadow, filterConfig.shadow);
        if (shadow) {
            // apply to the first path
            // #ZC2229
            let effectElementIndex = pick(handles[0]._effectElementIndex, 0) + 1;
            ele.select(`path:nth-child(${effectElementIndex})`).attr('filter', svgBoxShadow(shadow, chart));
        }
    }
}
